import requests, xml.etree.ElementTree as ET
from urllib.parse import urljoin
import sys

base = "https://scaa.us"
robots_url = base + "/robots.txt"

def fetch_url(url):
    try:
        r = requests.get(url, timeout=15, allow_redirects=True)
        return r.status_code, r.headers, r.text
    except Exception as e:
        return None, {}, f"EXCEPTION: {e}"

def print_header(title):
    print("\n" + "="*80)
    print(title)
    print("="*80)

print_header(f"Robots.txt: {robots_url}")
status, headers, body = fetch_url(robots_url)
sitemaps = []
if status:
    print(f"HTTP {status}")
    ct = headers.get('Content-Type','')
    print(f"Content-Type: {ct}")
    snippet = body[:8000]
    print("\nContent snippet (ilk 8000 karakter):\n")
    print(snippet)
    for line in body.splitlines():
        line_stripped = line.strip()
        if not line_stripped or line_stripped.startswith('#'):
            continue
        if line_stripped.lower().startswith('sitemap:'):
            s = line_stripped.split(':',1)[1].strip()
            sitemaps.append(s)
    # collect Disallow/Allow lines for quick view
    disallows = []
    allows = []
    for line in body.splitlines():
        ls = line.strip()
        if ls.lower().startswith('disallow:'):
            disallows.append(ls.split(':',1)[1].strip())
        if ls.lower().startswith('allow:'):
            allows.append(ls.split(':',1)[1].strip())
    if disallows:
        print("\nRobots: Disallow list (örnekler):")
        for d in disallows[:20]:
            print("-", d)
    if allows:
        print("\nRobots: Allow list (örnekler):")
        for a in allows[:20]:
            print("-", a)
else:
    print(f"robots.txt erişilemedi veya hata: {body}")

if not sitemaps:
    sitemaps = [urljoin(base, "/sitemap.xml")]

for s in sitemaps:
    print_header(f"Sitemap: {s}")
    status, headers, body = fetch_url(s)
    if status is None:
        print("Erişim hatası:", body)
        continue
    print(f"HTTP {status}")
    ct = headers.get('Content-Type','')
    print(f"Content-Type: {ct}")
    is_xml = 'xml' in ct.lower() or body.strip().startswith('<')
    if is_xml:
        try:
            root = ET.fromstring(body.encode('utf-8'))
            locs = []
            for elem in root.iter():
                tag = elem.tag
                if tag.lower().endswith('loc'):
                    if elem.text:
                        locs.append(elem.text.strip())
            print(f"Toplam <loc> öğesi: {len(locs)}")
            for i, loc in enumerate(locs[:50], start=1):
                print(f"{i}. {loc}")
            if len(locs) > 50:
                print("... (ilk 50 gösteriliyor)")
        except Exception as e:
            print("XML parse hatası:", e)
            print("İçerik snippet (ilk 2000 karakter):")
            print(body[:2000])
    else:
        print("Sitemap muhtemelen düz metin veya farklı format. İçerik snippet (ilk 2000 karakter):")
        print(body[:2000])

print_header("Ana sayfa erişim bilgisi")
try:
    r = requests.get(base, timeout=15)
    print("Ana sayfa HTTP", r.status_code)
    print("Ana sayfa Content-Type:", r.headers.get('Content-Type',''))
except Exception as e:
    print("Ana sayfa erişim hatası:", e)

print("\nİşlem tamamlandı.")
